SELECT MAX(BOARD_NO) FROM WEB_BOARD

INSERT
INTO
		WEB_BOARD
		(
		USER_NO
	  , BOARD_TITLE
	  , BOARD_CONTENT	
		)
VALUES
		(
		#{userNo}
	  , #{boardTitle}	
	  , #{boardContent}	
		)

INSERT
INTO
		WEB_ATTACHMENT
		(
		REF_BNO
	 , ORIGIN_NAME
	 , CHANGE_NAME
	 , FILE_PATH
	 , BOARD_TYPE
	 , FILE_LEVEL	
		)
VALUES
		(
		#{refBno}
	, #{originName}
	, #{changeName}	
	, #{filePath}	
	, #{boardType}	
	, #{fileLevel}	

		)

mapper.update:
UPDATE
		WEB_BOARD
SET
		BOARD_TITLE = #{boardTitle}
	  , BOARD_CONTENT = #{boardContent}			
WHERE
		STATUS = 'N'
AND
		BOARD_NO = #{boardNo}		
AND
		USER_NO = #{userNo}

