		SELECT SEQ_IMAGE.NEXTVAL FROM DUAL


INSERT
INTO
		WEB_IMAGE_BOARD
		(
		BOARD_NO
	  ,	BOARD_TITLE
	  , BOARD_CONTENT
	  , BOARD_WRITER
		)
VALUES
		(
		#{boardNo}
	 , #{boardTitle}
	 , #{boardContent}
	 , #{userNo}	
		)

	INSERT
	INTO
			WEB_REPLY
			(
			REPLY_NO
		  , REF_BNO
		  , REPLY_CONTENT
		  , REPLY_WRITER
			)
VALUES
